625 static bool isKnownNonZeroFromAssume(const Value *V, const SimplifyQuery &Q) {
626   // Use of assumptions is context-sensitive. If we don't have a context, we
627   // cannot use them!
628   if (!Q.AC || !Q.CxtI)
